#include <bits/stdc++.h>
using namespace std;

int par[1001];
int find(int x){ return par[x]==x?x:par[x]=find(par[x]); }

int main() {
    ios_base::sync_with_stdio(false); cin.tie(NULL);
    int n, m; cin >> n >> m;
    for(int i=1;i<=n;i++) par[i]=i;
    for(int i=0;i<m;i++){
        int u,v; cin >> u >> v;
        int ru=find(u), rv=find(v);
        if(ru!=rv) par[ru]=rv;
    }
    int cnt=0;
    for(int i=1;i<=n;i++) if(find(i)==i) cnt++;
    cout << cnt << "\n";
    return 0;
}
